 29	        await dbContext.Suppliers.AsNoTracking().Where(supplier => supplier.WorkspaceId == workspaceId &&
 30	            supplier.ArchivedAtUtc == null).OrderBy(supplier => supplier.Name).ThenBy(supplier => supplier.Id)
 31	            .ToListAsync(cancellationToken);
 32	
 33	    /// <inheritdoc />
 34	    public Task<Supplier?> FindAsync(Guid workspaceId, Guid supplierId, CancellationToken cancellationToken) =>
 35	        dbContext.Suppliers.SingleOrDefaultAsync(supplier => supplier.WorkspaceId == workspaceId && supplier.Id == supplierId,
 36	            cancellationToken);
 37	
 38	    /// <inheritdoc />
 39	    public async Task<bool> ArchiveAsync(Guid workspaceId, Guid supplierId, DateTimeOffset archivedAtUtc,
 40	        CancellationToken cancellationToken)
 41	    {
 42	        var supplier = await dbContext.Suppliers.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
 43	            item.Id == supplierId, cancellationToken);
 44	        if (supplier is null) return false;
 45	        supplier.Archive(archivedAtUtc);
 46	        await dbContext.SaveChangesAsync(cancellationToken);
 47	        return true;
 48	    }
 49	
 50	    /// <inheritdoc />
 51	    public async Task SaveChangesAsync(CancellationToken cancellationToken) => await dbContext.SaveChangesAsync(cancellationToken);
 52	}
