 63	        var secondToken = await RegisterAsync();
 64	        using var firstCreate = await SendAsync(HttpMethod.Post, "/api/suppliers", firstToken, new CreateSupplierRequest("Shared"));
 65	        var firstSupplier = await firstCreate.Content.ReadFromJsonAsync<SupplierResponse>();
 66	        using var secondCreate = await SendAsync(HttpMethod.Post, "/api/suppliers", secondToken, new CreateSupplierRequest(" shared "));
 67	        using var secondList = await SendAsync(HttpMethod.Get, "/api/suppliers", secondToken);
 68	        using var crossArchive = await SendAsync(HttpMethod.Delete, $"/api/suppliers/{firstSupplier!.Id}", secondToken);
 69	        Assert.Equal(HttpStatusCode.Created, firstCreate.StatusCode);
