 78	    {
 79	        var session = await RegisterSessionAsync();
 80	        var suffix = Guid.NewGuid().ToString("N");
 81	        var firstRequest = SendAsync(HttpMethod.Post, "/api/suppliers", session.AccessToken, new CreateSupplierRequest($"Supplier-{suffix}"));
 82	        var secondRequest = SendAsync(HttpMethod.Post, "/api/suppliers", session.AccessToken, new CreateSupplierRequest($" supplier-{suffix.ToUpperInvariant()} "));
 83	
 84	        var responses = await Task.WhenAll(firstRequest, secondRequest);
 85	        using var firstResponse = responses[0];
 86	        using var secondResponse = responses[1];
 87	
 88	        Assert.Single(responses, response => response.StatusCode == HttpStatusCode.Created);
 89	        Assert.Single(responses, response => response.StatusCode == HttpStatusCode.Conflict);
 90	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
 91	        var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
 92	        Assert.Equal(1, await dbContext.Suppliers.CountAsync(supplier => supplier.WorkspaceId == session.User.Workspace.Id));
