106	    private async Task<HttpResponseMessage> SendAsync(HttpMethod method, string path, string token, object? content = null)
107	    {
108	        using var request = new HttpRequestMessage(method, path);
109	        request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
110	        if (content is not null) request.Content = JsonContent.Create(content);
111	        return await _client.SendAsync(request);
112	    }
