 14	/// <summary>Verifies workspace-scoped supplier API behavior against SQL Server.</summary>
 15	public sealed class SupplierEndpointsTests : IClassFixture<AuthenticatedApiFixture>
 16	{
 17	    private readonly HttpClient _client;
 18	    private readonly AuthenticatedApiFixture _fixture;
 19	
 20	    /// <summary>Initializes the test client.</summary>
 21	    public SupplierEndpointsTests(AuthenticatedApiFixture fixture)
 22	    {
 23	        _fixture = fixture;
 24	        _client = fixture.Factory.CreateClient(new WebApplicationFactoryClientOptions { HandleCookies = false });
 25	    }
 26	
 27	    /// <summary>Rejects unauthenticated supplier requests.</summary>
 28	    [Fact]
 29	    public async Task List_WithoutAccessToken_ReturnsUnauthorized()
 30	    {
 31	        using var response = await _client.GetAsync("/api/suppliers");
 32	        Assert.Equal(HttpStatusCode.Unauthorized, response.StatusCode);
 33	    }
 34	
 35	    /// <summary>Creates, lists, archives, and permanently reserves a normalized name through the database unique index.</summary>
 36	    [Fact]
 37	    public async Task SupplierLifecycle_UsesNormalizedNameAndKeepsArchivedNameReserved()
 38	    {
 39	        var session = await RegisterSessionAsync();
 40	        var token = session.AccessToken;
 41	        using var created = await SendAsync(HttpMethod.Post, "/api/suppliers", token, new CreateSupplierRequest("  Acme Supply  "));
 42	        var supplier = await created.Content.ReadFromJsonAsync<SupplierResponse>();
 43	        Assert.Equal(HttpStatusCode.Created, created.StatusCode);
 44	        Assert.Equal("Acme Supply", supplier!.Name);
 45	        using var listed = await SendAsync(HttpMethod.Get, "/api/suppliers", token);
 46	        Assert.Single(await listed.Content.ReadFromJsonAsync<List<SupplierResponse>>() ?? []);
 47	        using var archived = await SendAsync(HttpMethod.Delete, $"/api/suppliers/{supplier.Id}", token);
 48	        using var archivedAgain = await SendAsync(HttpMethod.Delete, $"/api/suppliers/{supplier.Id}", token);
 49	        using var duplicate = await SendAsync(HttpMethod.Post, "/api/suppliers", token, new CreateSupplierRequest(" acme supply "));
 50	        Assert.Equal(HttpStatusCode.NoContent, archived.StatusCode);
 51	        Assert.Equal(HttpStatusCode.NoContent, archivedAgain.StatusCode);
 52	        Assert.Equal(HttpStatusCode.Conflict, duplicate.StatusCode);
 53	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
 54	        var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
 55	        Assert.Equal(1, await dbContext.Suppliers.CountAsync(supplier => supplier.WorkspaceId == session.User.Workspace.Id));
 56	    }
 57	
 58	    /// <summary>Enforces workspace isolation while allowing the same name in different workspaces.</summary>
 59	    [Fact]
 60	    public async Task Suppliers_AreIsolatedByWorkspace()
 61	    {
 62	        var firstToken = await RegisterAsync();
 63	        var secondToken = await RegisterAsync();
 64	        using var firstCreate = await SendAsync(HttpMethod.Post, "/api/suppliers", firstToken, new CreateSupplierRequest("Shared"));
 65	        var firstSupplier = await firstCreate.Content.ReadFromJsonAsync<SupplierResponse>();
 66	        using var secondCreate = await SendAsync(HttpMethod.Post, "/api/suppliers", secondToken, new CreateSupplierRequest(" shared "));
 67	        using var secondList = await SendAsync(HttpMethod.Get, "/api/suppliers", secondToken);
 68	        using var crossArchive = await SendAsync(HttpMethod.Delete, $"/api/suppliers/{firstSupplier!.Id}", secondToken);
 69	        Assert.Equal(HttpStatusCode.Created, firstCreate.StatusCode);
 70	        Assert.Equal(HttpStatusCode.Created, secondCreate.StatusCode);
 71	        Assert.Single(await secondList.Content.ReadFromJsonAsync<List<SupplierResponse>>() ?? []);
 72	        Assert.Equal(HttpStatusCode.NotFound, crossArchive.StatusCode);
 73	    }
 74	
 75	    /// <summary>Maps a same-workspace name race through the database unique index to one creation and one conflict.</summary>
 76	    [Fact]
 77	    public async Task Create_ConcurrentNormalizedNameRequests_CreateOneSupplierAndReturnOneConflict()
 78	    {
 79	        var session = await RegisterSessionAsync();
 80	        var suffix = Guid.NewGuid().ToString("N");
 81	        var firstRequest = SendAsync(HttpMethod.Post, "/api/suppliers", session.AccessToken, new CreateSupplierRequest($"Supplier-{suffix}"));
 82	        var secondRequest = SendAsync(HttpMethod.Post, "/api/suppliers", session.AccessToken, new CreateSupplierRequest($" supplier-{suffix.ToUpperInvariant()} "));
 83	
 84	        var responses = await Task.WhenAll(firstRequest, secondRequest);
 85	        using var firstResponse = responses[0];
 86	        using var secondResponse = responses[1];
 87	
 88	        Assert.Single(responses, response => response.StatusCode == HttpStatusCode.Created);
 89	        Assert.Single(responses, response => response.StatusCode == HttpStatusCode.Conflict);
 90	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
 91	        var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
 92	        Assert.Equal(1, await dbContext.Suppliers.CountAsync(supplier => supplier.WorkspaceId == session.User.Workspace.Id));
 93	    }
 94	
 95	    private async Task<string> RegisterAsync() => (await RegisterSessionAsync()).AccessToken;
 96	
 97	    private async Task<AuthenticationResponse> RegisterSessionAsync()
 98	    {
 99	        var suffix = Guid.NewGuid().ToString("N");
100	        using var response = await _client.PostAsJsonAsync("/api/auth/register", new RegisterUserCommand($"User {suffix}", $"user-{suffix}@example.test", "Password!12345"));
101	        var session = await response.Content.ReadFromJsonAsync<AuthenticationResponse>();
102	        Assert.Equal(HttpStatusCode.OK, response.StatusCode);
103	        return session!;
104	    }
105	
106	    private async Task<HttpResponseMessage> SendAsync(HttpMethod method, string path, string token, object? content = null)
107	    {
108	        using var request = new HttpRequestMessage(method, path);
109	        request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
110	        if (content is not null) request.Content = JsonContent.Create(content);
111	        return await _client.SendAsync(request);
112	    }
113	}
